import { useState, useEffect } from "react";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { motion, AnimatePresence } from "framer-motion";
import { 
  User as UserIcon, Mail, Shield, ShieldCheck, CheckCircle, 
  Loader2, Calendar, MapPin, XCircle, Heart, Settings as SettingsIcon,
  LogOut, Clock, ExternalLink, Trash2
} from "lucide-react";
import { useAuth } from "@/context/AuthContext";
import { api } from "@/lib/api";
import { toast } from "sonner";
import { Link } from "react-router-dom";

const Profile = () => {
  const { user, token, logout } = useAuth();
  const [activeSection, setActiveSection] = useState("overview");
  const [registrations, setRegistrations] = useState<any[]>([]);
  const [wishlist, setWishlist] = useState<any[]>([]);
  const [tickets, setTickets] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const fetchUserData = async () => {
    if (!user?.id) return;
    setLoading(true);
    try {
      const [regsRes, wishRes, ticketsRes] = await Promise.all([
        api.get(`/registrations/user/${user.id}`, token || undefined),
        api.get(`/wishlist/user/${user.id}`, token || undefined),
        api.get(`/tickets/user/${user.id}`, token || undefined)
      ]);

      if (regsRes.success) setRegistrations(regsRes.data);
      if (wishRes.success) setWishlist(wishRes.data);
      if (ticketsRes.success) setTickets(ticketsRes.data);
    } catch (error) {
      toast.error("Failed to fetch user data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUserData();
  }, [user?.id, token]);

  const handleCancelRegistration = async (regId: string) => {
    setActionLoading(regId);
    try {
      const res = await api.delete(`/registrations/${regId}`, token || undefined);
      if (res.success) {
        toast.success("Registration cancelled");
        fetchUserData();
      }
    } catch (error) {
      toast.error("Cancellation failed");
    } finally {
      setActionLoading(null);
    }
  };

  const handleRemoveFromWishlist = async (eventId: string) => {
    setActionLoading(eventId);
    try {
      const res = await api.delete(`/wishlist/remove?eventId=${eventId}`, token || undefined);
      if (res.success) {
        toast.success("Removed from wishlist");
        fetchUserData();
      }
    } catch (error) {
      toast.error("Wishlist removal failed");
    } finally {
      setActionLoading(null);
    }
  };

  if (!user) return null;

  const sections = [
    { id: "overview", label: "Overview", icon: UserIcon },
    { id: "registrations", label: "My Registrations", icon: Calendar },
    { id: "wishlist", label: "Saved Events", icon: Heart },
    { id: "tickets", label: "Event Tickets", icon: CheckCircle },
    { id: "settings", label: "Settings", icon: SettingsIcon },
  ];

  const profileOverview = [
    { icon: UserIcon, label: "Full Name", value: user.name },
    { icon: Mail, label: "Email Address", value: user.email },
    { icon: Shield, label: "Account Role", value: user.role.toUpperCase() },
    { icon: Clock, label: "Member Since", value: new Date(user.createdAt || Date.now()).toLocaleDateString() },
  ];

  return (
    <DashboardLayout role={user.role}>
      <div className="max-w-6xl mx-auto py-8 px-4">
        <header className="mb-12">
           <h1 className="text-4xl font-black text-foreground tracking-tighter mb-2 italic">Student Profile</h1>
           <p className="text-muted-foreground font-medium">Manage your personal information and campus activities.</p>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Tabs Sidebar */}
          <div className="space-y-2">
            {sections.map((s) => (
              <button
                key={s.id}
                onClick={() => setActiveSection(s.id)}
                className={`w-full flex items-center gap-3 px-5 py-4 rounded-2xl text-sm font-black transition-all ${
                  activeSection === s.id 
                    ? "bg-primary text-white shadow-lg shadow-primary/20 translate-x-1" 
                    : "bg-card hover:bg-muted text-muted-foreground"
                }`}
              >
                <s.icon className="w-5 h-5" />
                {s.label}
              </button>
            ))}
            <button 
              onClick={logout}
              className="w-full flex items-center gap-3 px-5 py-4 rounded-2xl text-sm font-black text-destructive hover:bg-destructive/5 transition-all mt-8"
            >
              <LogOut className="w-5 h-5" />
              Sign Out
            </button>
          </div>

          {/* Main Content Area */}
          <div className="lg:col-span-3 min-h-[500px]">
            <AnimatePresence mode="wait">
              {activeSection === "overview" && (
                <motion.div
                  key="overview"
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                  className="space-y-6"
                >
                  <div className="bg-card rounded-3xl border border-border/50 p-8 shadow-xl shadow-foreground/5 relative overflow-hidden">
                    <div className="flex items-center gap-10">
                      <div className="w-32 h-32 rounded-3xl bg-gradient-to-br from-primary to-indigo-600 border-4 border-card shadow-2xl flex items-center justify-center text-4xl font-black text-white shrink-0 relative group cursor-pointer overflow-hidden">
                        {user.picture ? <img src={user.picture} alt={user.name} className="w-full h-full object-cover group-hover:opacity-50 transition-opacity" /> : <span className="group-hover:opacity-50 transition-opacity">{user.name.charAt(0)}</span>}
                        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/40 backdrop-blur-sm">
                          <span className="text-xs tracking-widest uppercase">Upload</span>
                        </div>
                      </div>
                      <div className="flex-1 min-w-0">
                        <h2 className="text-3xl font-black text-foreground tracking-tighter mb-1">{user.name}</h2>
                        <p className="text-muted-foreground font-medium mb-4 opacity-70 italic">{user.email}</p>
                        <div className="flex gap-2">
                          <span className="px-4 py-1.5 rounded-full bg-primary/10 text-primary border border-primary/20 text-[10px] font-black uppercase tracking-widest">
                            {user.role}
                          </span>
                          <span className="px-4 py-1.5 rounded-full bg-green-500/10 text-green-500 border border-green-500/20 text-[10px] font-black uppercase tracking-widest">
                            Verified Account
                          </span>
                        </div>
                      </div>
                    </div>
                  </div>

                  <form 
                    onSubmit={async (e) => {
                      e.preventDefault();
                      setActionLoading('update-profile');
                      const formData = new FormData(e.currentTarget);
                      const data = {
                        name: formData.get('name'),
                        department: formData.get('department'),
                      };
                      try {
                        const res = await api.put('/users/update-profile', data, token || undefined);
                        if (res.success) {
                          toast.success("Profile updated successfully");
                          // You would typically update local auth state here as well
                        } else {
                          toast.error(res.message || "Failed to update profile");
                        }
                      } catch (error) {
                        toast.error("An error occurred");
                      } finally {
                        setActionLoading(null);
                      }
                    }}
                    className="bg-card rounded-3xl border border-border/50 p-8 shadow-xl shadow-foreground/5 grid grid-cols-1 md:grid-cols-2 gap-8"
                  >
                     <div className="space-y-2">
                        <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block opacity-60">Full Name</label>
                        <input name="name" defaultValue={user.name} className="w-full bg-muted/30 border border-border/50 rounded-xl px-4 py-3 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all" />
                     </div>
                     <div className="space-y-2">
                        <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block opacity-60">Email Address</label>
                        <input name="email" defaultValue={user.email} disabled className="w-full bg-muted/10 border border-border/10 rounded-xl px-4 py-3 text-sm font-bold text-muted-foreground cursor-not-allowed" />
                     </div>
                     <div className="space-y-2">
                        <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block opacity-60">Department</label>
                        <input name="department" defaultValue={user.department || ''} placeholder="e.g. Computer Science" className="w-full bg-muted/30 border border-border/50 rounded-xl px-4 py-3 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all" />
                     </div>
                     <div className="space-y-2">
                        <label className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block opacity-60">Member Since</label>
                        <input readOnly value={new Date(user.createdAt || Date.now()).toLocaleDateString()} className="w-full bg-muted/10 border border-border/10 rounded-xl px-4 py-3 text-sm font-bold text-muted-foreground cursor-not-allowed" />
                     </div>
                     
                     <div className="col-span-1 md:col-span-2 pt-4 flex justify-end">
                        <button 
                          type="submit" 
                          disabled={actionLoading === 'update-profile'}
                          className="px-8 py-3.5 rounded-2xl bg-primary text-white font-black text-xs uppercase tracking-widest hover:bg-primary/90 transition-all shadow-lg shadow-primary/20 flex items-center gap-2"
                        >
                          {actionLoading === 'update-profile' && <Loader2 className="w-4 h-4 animate-spin" />}
                          Save Changes
                        </button>
                     </div>
                  </form>
                </motion.div>
              )}

              {activeSection === "registrations" && (
                <motion.div
                  key="registrations"
                  initial={{ opacity: 0, x: 20 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                  className="space-y-6"
                >
                  <div className="flex items-center justify-between mb-2">
                    <h2 className="text-2xl font-black text-foreground tracking-tighter">My Active Registrations</h2>
                    <span className="bg-primary/10 px-3 py-1 rounded-lg text-primary text-[10px] font-black uppercase tracking-widest">{registrations.length} Total</span>
                  </div>

                  <div className="grid grid-cols-1 gap-4">
                    {registrations.length > 0 ? registrations.map((r: any) => (
                      <div key={r.id} className="bg-card rounded-3xl border border-border/50 p-6 flex flex-col md:flex-row items-center justify-between gap-6 hover:border-primary/30 transition-all group">
                         <div className="flex items-center gap-5 w-full md:w-auto">
                            <div className="w-14 h-14 rounded-2xl bg-muted flex items-center justify-center text-muted-foreground flex-shrink-0">
                               <Calendar className="w-6 h-6" />
                            </div>
                            <div className="min-w-0">
                               <h3 className="font-black text-foreground text-lg tracking-tight group-hover:text-primary transition-colors truncate">{r.event?.title}</h3>
                               <div className="flex items-center gap-4 mt-1">
                                  <div className="flex items-center gap-1.5 text-xs text-muted-foreground font-bold">
                                     <Clock className="w-3.5 h-3.5" /> {r.event?.date}
                                  </div>
                                  <div className="flex items-center gap-1.5 text-xs text-muted-foreground font-bold">
                                     <MapPin className="w-3.5 h-3.5" /> {r.event?.venue}
                                  </div>
                               </div>
                            </div>
                         </div>
                         <div className="flex items-center gap-3 w-full md:w-auto">
                            <Link to={`/events/${r.eventId}`} className="flex-1 md:flex-none px-6 py-2.5 rounded-xl bg-primary/10 text-primary text-xs font-black uppercase tracking-widest hover:bg-primary hover:text-white transition-all text-center">
                               View Event
                            </Link>
                            <button 
                              onClick={() => handleCancelRegistration(r.id)}
                              disabled={actionLoading === r.id}
                              className="w-11 h-11 flex items-center justify-center rounded-xl bg-destructive/10 text-destructive hover:bg-destructive hover:text-white transition-all active:scale-95"
                            >
                               {actionLoading === r.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <XCircle className="w-5 h-5" />}
                            </button>
                         </div>
                      </div>
                    )) : (
                      <div className="py-20 bg-card rounded-3xl border border-dashed border-border flex flex-col items-center">
                         <Calendar className="w-16 h-16 text-muted-foreground opacity-20 mb-4" />
                         <p className="text-muted-foreground font-bold tracking-tight">No events registered yet.</p>
                         <Link to="/student/explore" className="mt-4 text-primary text-sm font-black uppercase tracking-widest underline underline-offset-8">Browse Events</Link>
                      </div>
                    )}
                  </div>
                </motion.div>
              )}

              {activeSection === "wishlist" && (
                 <motion.div
                   key="wishlist"
                   initial={{ opacity: 0, x: 20 }}
                   animate={{ opacity: 1, x: 0 }}
                   exit={{ opacity: 0, x: -20 }}
                   className="space-y-6"
                 >
                   <div className="flex items-center justify-between mb-2">
                    <h2 className="text-2xl font-black text-foreground tracking-tighter">Event Wishlist</h2>
                    <span className="bg-accent/10 px-3 py-1 rounded-lg text-accent text-[10px] font-black uppercase tracking-widest">{wishlist.length} Saved</span>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                    {wishlist.length > 0 ? wishlist.map((item: any) => (
                      <div key={item._id} className="bg-card rounded-3xl border border-border/50 overflow-hidden shadow-xl shadow-foreground/5 hover:border-accent/30 transition-all group relative">
                         <div className="h-40 relative">
                            <img src={item.imageUrl || "https://images.unsplash.com/photo-1501281668745-f7f57925c3b4?w=800"} alt={item.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                            <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
                            <button 
                               onClick={() => handleRemoveFromWishlist(item._id)}
                               disabled={actionLoading === item._id}
                               className="absolute top-4 right-4 w-10 h-10 rounded-xl bg-white/20 backdrop-blur-md flex items-center justify-center text-white hover:bg-destructive hover:text-white transition-all shadow-xl"
                            >
                               {actionLoading === item._id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-5 h-5" />}
                            </button>
                         </div>
                         <div className="p-6">
                            <h3 className="font-black text-foreground text-lg tracking-tight mb-2 truncate group-hover:text-accent transition-colors">{item.title}</h3>
                            <div className="flex items-center gap-2 text-xs text-muted-foreground font-bold mb-6">
                               <Calendar className="w-3.5 h-3.5" /> {item.date}
                            </div>
                            <Link to={`/events/${item._id}`} className="w-full flex items-center justify-center gap-2 h-11 rounded-xl bg-accent text-white text-xs font-black uppercase tracking-widest shadow-lg shadow-accent/20 hover:bg-accent/90 transition-all active:scale-95">
                               View Event <ExternalLink className="w-3.5 h-3.5" />
                            </Link>
                         </div>
                      </div>
                    )) : (
                      <div className="col-span-2 py-20 bg-card rounded-3xl border border-dashed border-border flex flex-col items-center">
                         <Heart className="w-16 h-16 text-muted-foreground opacity-20 mb-4" />
                         <p className="text-muted-foreground font-bold tracking-tight">Your wishlist is empty.</p>
                      </div>
                    )}
                  </div>
                 </motion.div>
              )}

              {activeSection === "tickets" && (
                 <motion.div
                   key="tickets"
                   initial={{ opacity: 0, x: 20 }}
                   animate={{ opacity: 1, x: 0 }}
                   exit={{ opacity: 0, x: -20 }}
                   className="space-y-6"
                 >
                   <div className="flex items-center justify-between mb-2">
                    <h2 className="text-2xl font-black text-foreground tracking-tighter">My Event Tickets</h2>
                    <span className="bg-primary/10 px-3 py-1 rounded-lg text-primary text-[10px] font-black uppercase tracking-widest">{tickets.length} Tickets</span>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {tickets.length > 0 ? tickets.map((t: any) => (
                      <div key={t.id} className="bg-card rounded-3xl border border-border/50 overflow-hidden shadow-xl shadow-foreground/5 flex flex-col relative group">
                         <div className="p-6 pb-8 border-b border-border/50 border-dashed relative">
                            {/* Ticket cutouts */}
                            <div className="absolute -left-3 bottom-[-12px] w-6 h-6 rounded-full bg-background border-r border-t border-border/50 -rotate-45" />
                            <div className="absolute -right-3 bottom-[-12px] w-6 h-6 rounded-full bg-background border-l border-t border-border/50 rotate-45" />
                            
                            <div className="flex justify-between items-start mb-6">
                               <div>
                                  <span className="bg-green-500/10 text-green-500 text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded-md mb-3 inline-block">Confirmed</span>
                                  <h3 className="font-black text-foreground text-xl tracking-tight line-clamp-2">{t.event?.title}</h3>
                               </div>
                               <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary shrink-0">
                                  <CheckCircle className="w-6 h-6" />
                               </div>
                            </div>
                            
                            <div className="grid grid-cols-2 gap-4">
                               <div>
                                  <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block mb-1 opacity-60">Date & Time</span>
                                  <p className="text-sm font-bold text-foreground flex items-center gap-1.5"><Clock className="w-3.5 h-3.5 text-primary" /> {t.event?.date}</p>
                               </div>
                               <div>
                                  <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block mb-1 opacity-60">Venue</span>
                                  <p className="text-sm font-bold text-foreground flex items-center gap-1.5"><MapPin className="w-3.5 h-3.5 text-primary" /> {t.event?.venue || 'TBA'}</p>
                               </div>
                            </div>
                         </div>
                         
                         <div className="p-6 bg-muted/20 flex items-center justify-between">
                            <div>
                               <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest block mb-1 opacity-60">Ticket ID</span>
                               <p className="font-mono text-sm font-bold text-foreground bg-muted px-2 py-1 rounded-md">{t.ticketNumber || `TCK-${t.id.substring(0, 8).toUpperCase()}`}</p>
                            </div>
                            <div className="w-16 h-16 bg-white p-1 rounded-lg shadow-sm">
                               {/* Mock QR Code using CSS since we don't have a library */}
                               <div className="w-full h-full bg-[url('https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=EventraTicket')] bg-cover bg-center opacity-80 mix-blend-multiply" />
                            </div>
                         </div>
                      </div>
                    )) : (
                      <div className="col-span-2 py-20 bg-card rounded-3xl border border-dashed border-border flex flex-col items-center">
                         <div className="w-20 h-20 rounded-full bg-muted flex items-center justify-center mb-6">
                            <CheckCircle className="w-10 h-10 text-muted-foreground opacity-30" />
                         </div>
                         <h3 className="text-xl font-black text-foreground tracking-tighter mb-2">No Tickets Found</h3>
                         <p className="text-muted-foreground font-medium text-center max-w-md">You don't have any event tickets yet. Register for an event to get your access tickets.</p>
                         <Link to="/student/explore" className="mt-6 px-6 py-2.5 rounded-xl bg-primary text-white text-xs font-black uppercase tracking-widest hover:bg-primary/90 transition-all active:scale-95 shadow-lg shadow-primary/20">Find Events</Link>
                      </div>
                    )}
                  </div>
                 </motion.div>
              )}

              {activeSection === "settings" && (
                 <motion.div
                   key="settings"
                   initial={{ opacity: 0, x: 20 }}
                   animate={{ opacity: 1, x: 0 }}
                   exit={{ opacity: 0, x: -20 }}
                   className="space-y-6"
                 >
                   <div className="bg-card rounded-3xl border border-border/50 p-10 text-center">
                      <SettingsIcon className="w-16 h-16 text-muted-foreground opacity-20 mx-auto mb-6" />
                      <h2 className="text-2xl font-black text-foreground tracking-tighter mb-2 italic">Account Security</h2>
                      <p className="text-muted-foreground max-w-sm mx-auto font-medium">Profile editing and password change features are coming in the next update.</p>
                      
                      <div className="mt-10 pt-10 border-t border-border/50">
                         <Link to="/settings" className="px-8 py-3.5 rounded-2xl bg-muted font-black text-xs uppercase tracking-widest hover:bg-primary hover:text-white transition-all">Go to Global Settings</Link>
                      </div>
                   </div>
                 </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>
      </div>
    </DashboardLayout>
  );
};

export default Profile;
